document.addEventListener('DOMContentLoaded', () => {
        lucide.createIcons();
            renderWatchlist();
                renderOrderBook();
                    renderPositions();
                        renderHistory();
                            renderNews();
                                renderAnalytics();
                                    initChart();
                                    });

                                    async function connectWallet() {
                                        if (typeof window.ethereum !== 'undefined') {
                                                try {
                                                            const accounts = await window.ethereum.request({ method: 'eth_requestAccounts' });
                                                                        const account = accounts[0];
                                                                                    const balance = await window.ethereum.request({method: 'eth_getBalance', params: [account, 'latest']});
                                                                                                const ethBalance = (parseInt(balance, 16) / 1e18).toFixed(4);
                                                                                                            const shortAddress = account.substring(0, 6) + '...' + account.substring(38);
                                                                                                                        document.getElementById('walletAddress').textContent = shortAddress;
                                                                                                                                    document.getElementById('walletBalance').textContent = ethBalance + ' ETH';
                                                                                                                                                const btn = document.getElementById('connectWalletBtn');
                                                                                                                                                            btn.textContent = 'Connected';
                                                                                                                                                                        btn.disabled = true;
                                                                                                                                                                                } catch (error) {
                                                                                                                                                                                            console.error(error);
                                                                                                                                                                                                        alert('Failed to connect wallet');
                                                                                                                                                                                                                }
                                                                                                                                                                                                                    } else {
                                                                                                                                                                                                                            alert('MetaMask not installed');
                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                async function callClaudeAPI(prompt, context = {}) {
                                                                                                                                                                                                                                    if (CONFIG.FEATURES.MOCK_MODE) {
                                                                                                                                                                                                                                            return getMockAIResponse(prompt, context);
                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                    try {
                                                                                                                                                                                                                                                            const response = await fetch(`${CONFIG.API_BASE_URL}${CONFIG.CLAUDE_ENDPOINT}`, {
                                                                                                                                                                                                                                                                        method: 'POST',
                                                                                                                                                                                                                                                                                    headers: {'Content-Type': 'application/json'},
                                                                                                                                                                                                                                                                                                body: JSON.stringify({prompt, context, symbol: selected})
                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                if (!response.ok) throw new Error(`API error`);
                                                                                                                                                                                                                                                                                                                        return await response.json();
                                                                                                                                                                                                                                                                                                                            } catch (error) {
                                                                                                                                                                                                                                                                                                                                    console.error(error);
                                                                                                                                                                                                                                                                                                                                            return getMockAIResponse(prompt, context);
                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                }

